#include<bits/stdc++.h>
using namespace std;
char s[101];
int dp[101][101];
int main()
{
    scanf("%s",s+1);
    int n=strlen(s+1);
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=n;i++)
    {
        dp[i][i]=1;
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            if(s[l]==s[r])
            {
                dp[l][r]=dp[l][r-1];
            }
            for(int k=l;k<r;k++)
            {
                dp[l][r]=min(dp[l][r],dp[l][k]+dp[k+1][r]);
            }
        }
    }
    printf("%d",dp[1][n]);
    return 0;
}
